      const error = new Error(data.error || `请求失败: ${res.status}`);
      error.status = res.status;
      error.payload = data;
      throw error;
    }

    if (!res.body) throw new Error("浏览器不支持流式读取");

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buffer = "";

