export function createBootstrapController({
  state,
  setToken,
  resetUserSessionState,
  showAuth,
  showApp,
  renderUserBadge,
  setStatus,
  loadModels,
  loadServiceStatus,
  loadSettings,
  syncWebSearchToggleUi,
  loadConversations,
  selectConversation,
  renderMessages,
  setStreamingUi,
  applyServiceAvailability,
  resizeMessageInput,
  applyMobileUploadCollapse,
  request,
  initViewportLayout,
  initDesktopSidebarResize,
  renderThemeSelectors,
  bindEvents,
  clearAllWordExportPolls,
  closeSidebar,
  closeSettingsPanel,
  closeAdminPanel,
  hideServiceNoticeModal,
  SW_CLEANUP_KEY,
  cleanupLegacyServiceWorkers,
  ensureRenderLibraries,
}) {
  let viewportCleanup = null;
  let splitCleanup = null;

  function handleLogout() {
    clearAllWordExportPolls();
    state.wordExportGeneratingIds.clear();
    state.wordIntentSuggestions.clear();
    setToken("");
    resetUserSessionState(state);
    state.serviceNoticeShownSignature = "";
    setStreamingUi(false);
    closeSidebar();
    closeSettingsPanel();
    closeAdminPanel();
    hideServiceNoticeModal();
    showAuth();
  }

  async function bootApp() {
    showApp();
    renderUserBadge();
    setStatus("初始化中...");
    await loadModels();
    await loadServiceStatus();
    await loadSettings();
    syncWebSearchToggleUi();
    await loadConversations();
    if (state.conversations.length) await selectConversation(state.conversations[0].id);
    else renderMessages({ autoScroll: false });
    if (state.serviceStatus?.canUseAi) {
      setStatus("准备就绪");
    }
  }

  async function bootstrap() {
    const reloading = await cleanupLegacyServiceWorkers(SW_CLEANUP_KEY);
    if (reloading) return;
    try {
      await ensureRenderLibraries();
    } catch {
      // Markdown/math gracefully fall back to plain text if libs fail to load.
    }
    if (viewportCleanup) viewportCleanup();
    if (splitCleanup) splitCleanup();
    viewportCleanup = initViewportLayout();
    splitCleanup = initDesktopSidebarResize();
    renderThemeSelectors();
    bindEvents();
    setStreamingUi(false);
    syncWebSearchToggleUi();
    applyServiceAvailability();
    resizeMessageInput();
    applyMobileUploadCollapse();

    if (!state.token) {
      showAuth();
      return;
    }

    try {
      const data = await request("/api/auth/me");
      state.user = data.user;
      await bootApp();
    } catch {
      showAuth();
    }
  }

